+
+  .dark .glass-card:hover {
+    box-shadow:
+      0 4px 16px -2px oklch(0 0 0 / 0.4),
+      0 16px 40px -8px oklch(0 0 0 / 0.5);
+  }
+
+  /* Glass navbar with enhanced blur */
+  .glass-navbar {
+    background: oklch(1 0 0 / 0.75);
+    backdrop-filter: blur(20px) saturate(180%);
+    -webkit-backdrop-filter: blur(20px) saturate(180%);
+    border-bottom: 1px solid oklch(0.92 0.006 260 / 0.3);
+    transition: background 0.3s ease, backdrop-filter 0.3s ease;
+  }
+
+  .glass-navbar.scrolled {
+    background: oklch(1 0 0 / 0.9);
+    backdrop-filter: blur(24px) saturate(200%);
+    -webkit-backdrop-filter: blur(24px) saturate(200%);
+    box-shadow: 0 1px 3px oklch(0 0 0 / 0.06);
+  }
+
+  .dark .glass-navbar {
+    background: oklch(0.12 0.02 260 / 0.8);
+    border-bottom: 1px solid oklch(1 0 0 / 0.05);
+  }
+
+  .dark .glass-navbar.scrolled {
+    background: oklch(0.12 0.02 260 / 0.95);
+    box-shadow: 0 1px 3px oklch(0 0 0 / 0.3);
+  }
+
+  /* Glass modal with frosted effect */
+  .glass-modal {
+    background: oklch(1 0 0 / 0.9);
+    backdrop-filter: blur(40px) saturate(180%);
+    -webkit-backdrop-filter: blur(40px) saturate(180%);
+    border: 1px solid oklch(0.92 0.006 260 / 0.3);
+    border-radius: 24px;
+    box-shadow:
+      0 24px 48px -12px oklch(0 0 0 / 0.2),
+      0 0 0 1px oklch(1 0 0 / 0.5) inset;
+  }
+
+  .dark .glass-modal {
+    background: oklch(0.14 0.025 260 / 0.95);
+    border: 1px solid oklch(1 0 0 / 0.08);
+    box-shadow:
+      0 24px 48px -12px oklch(0 0 0 / 0.6),
+      0 0 0 1px oklch(1 0 0 / 0.03) inset;
+  }
+
+  /* ========================================================================
+     SHIMMER & SKELETON LOADING STATES
+     ======================================================================== */
+
+  .shimmer {
+    background: linear-gradient(
+      90deg,
+      oklch(0.96 0 0) 0%,
+      oklch(0.92 0 0) 50%,
+      oklch(0.96 0 0) 100%
+    );
+    background-size: 200% 100%;
+    animation: shimmer 1.5s ease-in-out infinite;
+  }
+
+  .dark .shimmer {
+    background: linear-gradient(
+      90deg,
+      oklch(0.18 0.02 260) 0%,
+      oklch(0.22 0.02 260) 50%,
+      oklch(0.18 0.02 260) 100%
+    );
+    background-size: 200% 100%;
+  }
+
+  .skeleton {
+    background: oklch(0.94 0.006 260);
+    border-radius: 8px;
+    position: relative;
+    overflow: hidden;
+  }
+
+  .skeleton::after {
+    content: "";
+    position: absolute;
+    inset: 0;
+    background: linear-gradient(
+      90deg,
+      transparent,
+      oklch(1 0 0 / 0.5),
+      transparent
+    );
+    animation: shimmer-sweep 1.5s ease-in-out infinite;
+  }
+
+  .dark .skeleton {
+    background: oklch(0.2 0.02 260);
+  }
+
+  .dark .skeleton::after {
+    background: linear-gradient(
+      90deg,
+      transparent,
+      oklch(1 0 0 / 0.08),
+      transparent
+    );
+  }
+
